        opts.type = "browserPopup";
        opts.id = scwin.popupID || "pupup";
        opts.width = 460;
        opts.height = 280;
        opts.popupName = 'FHL/FWB 결과 수신';

        rtnList = await $c.win.openPopup(win_url, opts, null);
        console.log("rtnList : " , rtnList);
    }
}
